#include <vector>
#include <cstring>

using namespace std;

class Solution {
    int rows[9], cols[9], boxes[9];

    bool backtrack(vector<vector<char>>& board) {
        int bestRow = -1, bestCol = -1;
        int maxPopcount = -1; // Maximizing popcount of combined mask minimizes candidates
        int bestBoxIdx = -1;
        int bestMask = 0;

        // 1. MRV Heuristic: Find the most constrained cell (fewest candidates)
        for (int r = 0; r < 9; r++) {
            for (int c = 0; c < 9; c++) {
                if (board[r][c] == '.') {
                    int boxIdx = (r / 3) * 3 + (c / 3);
                    int combinedMask = rows[r] | cols[c] | boxes[boxIdx];
                    int pop = __builtin_popcount(combinedMask);
                    if (pop > maxPopcount) {
                        maxPopcount = pop;
                        bestRow = r;
                        bestCol = c;
                        bestBoxIdx = boxIdx;
                        bestMask = combinedMask;
                    }
                }
            }
        }

        // If no empty cells remaining, we solved it!
        if (bestRow == -1) return true;

        // If the cell with fewest candidates has 0 candidates, backtrack
        if (maxPopcount == 9) return false;

        // 2. Try only the valid candidates using bitwise manipulations
        int candidates = ~bestMask & 0x1FF;
        while (candidates > 0) {
            int lsb = candidates & -candidates; // Extract the lowest set bit
            candidates ^= lsb;                   // Clear it
            int num = __builtin_ctz(lsb);        // Get the 0-based digit index

            int mask = 1 << num;

            // Set state
            rows[bestRow] |= mask;
            cols[bestCol] |= mask;
            boxes[bestBoxIdx] |= mask;
            board[bestRow][bestCol] = num + '1';

            if (backtrack(board)) return true;

            // Reset state (Backtrack)
            rows[bestRow] &= ~mask;
            cols[bestCol] &= ~mask;
            boxes[bestBoxIdx] &= ~mask;
            board[bestRow][bestCol] = '.';
        }

        return false;
    }

public:
    void solvePuzzle(vector<vector<char>>& board) {
        memset(rows, 0, sizeof(rows));
        memset(cols, 0, sizeof(cols));
        memset(boxes, 0, sizeof(boxes));

        // Pre-fill state masks for givens
        for (int r = 0; r < 9; r++) {
            for (int c = 0; c < 9; c++) {
                if (board[r][c] != '.') {
                    int num = board[r][c] - '1';
                    rows[r] |= (1 << num);
                    cols[c] |= (1 << num);
                    boxes[(r / 3) * 3 + (c / 3)] |= (1 << num);
                }
            }
        }

        backtrack(board);
    }
};

