import java.util.Arrays;

class Solution {
    private int[] rows = new int[9];
    private int[] cols = new int[9];
    private int[] boxes = new int[9];

    private boolean backtrack(char[][] board) {
        int bestRow = -1, bestCol = -1;
        int maxPopcount = -1;
        int bestBoxIdx = -1;
        int bestMask = 0;

        for (int r = 0; r < 9; r++) {
            for (int c = 0; c < 9; c++) {
                if (board[r][c] == '.') {
                    int boxIdx = (r / 3) * 3 + (c / 3);
                    int combinedMask = rows[r] | cols[c] | boxes[boxIdx];
                    int pop = Integer.bitCount(combinedMask);
                    if (pop > maxPopcount) {
                        maxPopcount = pop;
                        bestRow = r;
                        bestCol = c;
                        bestBoxIdx = boxIdx;
                        bestMask = combinedMask;
                    }
                }
            }
        }

        if (bestRow == -1) return true;
        if (maxPopcount == 9) return false;

        int candidates = ~bestMask & 0x1FF;
        while (candidates > 0) {
            int lsb = candidates & -candidates;
            candidates ^= lsb;
            int num = Integer.numberOfTrailingZeros(lsb);

            int mask = 1 << num;
            rows[bestRow] |= mask;
            cols[bestCol] |= mask;
            boxes[bestBoxIdx] |= mask;
            board[bestRow][bestCol] = (char) (num + '1');

            if (backtrack(board)) return true;

            rows[bestRow] &= ~mask;
            cols[bestCol] &= ~mask;
            boxes[bestBoxIdx] &= ~mask;
            board[bestRow][bestCol] = '.';
        }

        return false;
    }

    public void solvePuzzle(char[][] board) {
        Arrays.fill(rows, 0);
        Arrays.fill(cols, 0);
        Arrays.fill(boxes, 0);

        for (int r = 0; r < 9; r++) {
            for (int c = 0; c < 9; c++) {
                if (board[r][c] != '.') {
                    int num = board[r][c] - '1';
                    int mask = 1 << num;
                    rows[r] |= mask;
                    cols[c] |= mask;
                    boxes[(r / 3) * 3 + (c / 3)] |= mask;
                }
            }
        }
        backtrack(board);
    }
}

