class Solution {
    constructor() {
        this.rows = new Array(9).fill(0);
        this.cols = new Array(9).fill(0);
        this.boxes = new Array(9).fill(0);
    }

    bitCount(n) {
        let count = 0;
        while (n > 0) {
            count++;
            n &= n - 1;
        }
        return count;
    }

    ctz(n) {
        return Math.log2(n & -n) | 0;
    }

    backtrack(board) {
        let bestRow = -1, bestCol = -1;
        let maxPopcount = -1;
        let bestBoxIdx = -1;
        let bestMask = 0;

        for (let r = 0; r < 9; r++) {
            for (let c = 0; c < 9; c++) {
                if (board[r][c] === '.') {
                    const boxIdx = Math.floor(r / 3) * 3 + Math.floor(c / 3);
                    const combinedMask = this.rows[r] | this.cols[c] | this.boxes[boxIdx];
                    const pop = this.bitCount(combinedMask);
                    if (pop > maxPopcount) {
                        maxPopcount = pop;
                        bestRow = r;
                        bestCol = c;
                        bestBoxIdx = boxIdx;
                        bestMask = combinedMask;
                    }
                }
            }
        }

        if (bestRow === -1) return true;
        if (maxPopcount === 9) return false;

        let candidates = ~bestMask & 0x1FF;
        while (candidates > 0) {
            const lsb = candidates & -candidates;
            candidates ^= lsb;
            const num = this.ctz(lsb);

            const mask = 1 << num;
            this.rows[bestRow] |= mask;
            this.cols[bestCol] |= mask;
            this.boxes[bestBoxIdx] |= mask;
            board[bestRow][bestCol] = String.fromCharCode(num + 49); // '1' is 49 in ASCII

            if (this.backtrack(board)) return true;

            this.rows[bestRow] &= ~mask;
            this.cols[bestCol] &= ~mask;
            this.boxes[bestBoxIdx] &= ~mask;
            board[bestRow][bestCol] = '.';
        }

        return false;
    }

    solvePuzzle(board) {
        this.rows.fill(0);
        this.cols.fill(0);
        this.boxes.fill(0);

        for (let r = 0; r < 9; r++) {
            for (let c = 0; c < 9; c++) {
                if (board[r][c] !== '.') {
                    const num = board[r][c].charCodeAt(0) - 49;
                    const mask = 1 << num;
                    const boxIdx = Math.floor(r / 3) * 3 + Math.floor(c / 3);
                    this.rows[r] |= mask;
                    this.cols[c] |= mask;
                    this.boxes[boxIdx] |= mask;
                }
            }
        }
        this.backtrack(board);
    }
}
